PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?winRaceName WHERE {
  ?event wdt:P31 wd:Q561654 ; rdfs:label ?eventName ; wdt:P585 "1970-05-09" ^^ xsd:date .
  FILTER(lang(?eventName) = "en" && regex(?eventName , "Preakness" , "i"))
  ?event wdt:P1316 ?horse ; wdt:P154 ?pos .
  {
    SELECT(MAX(?pos) AS ?maxPos) WHERE {
      ?event wdt:P1316 ?h ; wdt:P154 ?pos .
    }
  }
  FILTER(?pos = ?maxPos - 1)
  ?horse wdt:P2037 ?jockey .
  ?winHorse wdt:P155 wd:Q1595808 ; wdt:P154 1 ; wdt:P2037 ?jockey .
  ?winRace wdt:P1316 ?winHorse ; rdfs:label ?winRaceName .
  FILTER(lang(?winRaceName) = "en")
}

