SELECT ?winRaceName WHERE {
  ?event wdt:P31 wd:Q561654;
         rdfs:label ?eventName;
         wdt:P585 ?eventDate.
  FILTER (lang(?eventName) = 'en' && REGEX(STR(?eventName), 'Preakness', 'i') && year(?eventDate) = 1970).
  ?event wdt:P1316 ?horse.
  ?horse wdt:P154 ?pos.
  {
    SELECT (MAX(?pos) AS ?maxPos) WHERE {
      ?event wdt:P1316 ?horseInEvent.
      ?horseInEvent wdt:P154 ?pos.
    }
  }
  FILTER (?pos = ?maxPos - 1).
  ?horse wdt:P2037 ?jockey.
  ?winHorse wdt:P155 wd:Q1595808;
            wdt:P154 1;
            wdt:P2037 ?jockey.
  ?winRace wdt:P1316 ?winHorse;
           rdfs:label ?winRaceName.
  FILTER (lang(?winRaceName) = 'en').
}

